import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { Upload, X } from 'lucide-react';
import { useState, useEffect } from 'react';
import Button from '../ui/Button';
import Input from '../ui/Input';
import Modal from '../ui/Modal';

const CATEGORIES = [
  'Electronics', 'Clothing', 'Food & Beverages', 'Furniture',
  'Automotive', 'Pharmaceuticals', 'Raw Materials', 'Machinery', 'Packaging', 'Other'
];

const productSchema = z.object({
  name: z.string().min(2, "Product name is required"),
  category: z.string().min(1, "Category is required"),
  description: z.string().optional(),
  price: z.coerce.number().positive("Price must be a positive number"),
});

export default function ProductForm({ isOpen, onClose, onSubmit, product, isLoading }) {
  const [imageFile, setImageFile] = useState(null);
  const [imagePreview, setImagePreview] = useState(null);

  const {
    register,
    handleSubmit,
    reset,
    formState: { errors }
  } = useForm({
    resolver: zodResolver(productSchema),
    defaultValues: {
      name: '',
      category: 'Electronics',
      description: '',
      price: '',
    }
  });

  useEffect(() => {
    if (isOpen) {
      if (product) {
        reset({
          name: product.name,
          category: product.category,
          description: product.description || '',
          price: product.price,
        });
        setImagePreview(product.imageUrl || null);
      } else {
        reset({ name: '', category: 'Electronics', description: '', price: '' });
        setImagePreview(null);
      }
      setImageFile(null);
    }
  }, [isOpen, product, reset]);

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      setImageFile(file);
      const reader = new FileReader();
      reader.onloadend = () => setImagePreview(reader.result);
      reader.readAsDataURL(file);
    }
  };

  const submitForm = (data) => {
    const formData = new FormData();
    formData.append('name', data.name);
    formData.append('category', data.category);
    formData.append('description', data.description || '');
    formData.append('price', data.price);

    if (imageFile) {
      formData.append('image', imageFile);
    }

    onSubmit(formData);
  };

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={product ? 'Edit Product' : 'Add New Product'} maxWidth="max-w-xl">
      <form onSubmit={handleSubmit(submitForm)} className="space-y-5">

        {/* Image Upload Area */}
        <div>
          <label className="block text-sm font-medium text-surface-300 mb-1.5">Product Image <span className="text-surface-500">(Optional)</span></label>
          <div className="relative border-2 border-dashed border-surface-700 rounded-xl bg-surface-900/50 hover:bg-surface-800 transition-colors group overflow-hidden h-40">
            {imagePreview ? (
              <div className="relative w-full h-full group-hover:opacity-80 transition-opacity flex items-center justify-center p-2">
                <img src={imagePreview} alt="Preview" className="max-w-full max-h-full object-contain rounded-lg" />
                <button
                  type="button"
                  onClick={(e) => {
                    e.preventDefault();
                    setImageFile(null);
                    setImagePreview(null);
                  }}
                  className="absolute top-2 right-2 p-1.5 bg-background/80 hover:bg-danger-500/90 text-surface-200 hover:text-white rounded-md transition-all shadow-md z-10"
                >
                  <X size={16} />
                </button>
              </div>
            ) : (
              <div className="w-full h-full flex flex-col items-center justify-center p-6 text-center cursor-pointer">
                <div className="p-3 bg-surface-800 rounded-full mb-3 text-surface-400 group-hover:text-primary-400 group-hover:bg-primary-500/10 transition-colors">
                  <Upload size={24} />
                </div>
                <p className="text-sm text-surface-200">
                  <span className="text-primary-400 font-medium">Click to upload</span> or drag and drop
                </p>
                <p className="text-xs text-surface-500 mt-1">PNG, JPG, WEBP up to 5MB</p>
                <input 
                  type="file" 
                  accept="image/*" 
                  onChange={handleImageChange}
                  className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                  title="Upload product image"
                />
              </div>
            )}
            {/* Make sure input covers the wrapper even when image is populated if we want click-to-replace, but X is better */}
          </div>
        </div>

        <Input 
          label="Product Name" 
          placeholder="e.g. Cisco C9200L Router"
          {...register('name')}
          error={errors.name?.message}
        />

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-surface-300 mb-1.5">Category</label>
            <select
              {...register('category')}
              className={`w-full h-10 rounded-lg border bg-surface-900/50 px-3 py-2 text-sm text-surface-100 focus:ring-2 focus:ring-primary-500/50 focus:border-primary-500/50 appearance-none outline-none transition-all ${errors.category ? 'border-danger-500/50 focus:border-danger-500/50 focus:ring-danger-500/50' : 'border-surface-700'}`}
            >
              {CATEGORIES.map(cat => <option key={cat} value={cat}>{cat}</option>)}
            </select>
            {errors.category && <p className="mt-1.5 text-xs text-danger-400">{errors.category.message}</p>}
          </div>

          <Input 
            label="Price (₹)" 
            type="number" 
            step="0.01"
            placeholder="0.00"
            {...register('price')}
            error={errors.price?.message}
          />
        </div>

        <div className="w-full">
          <label className="block text-sm font-medium text-surface-300 mb-1.5">Description <span className="text-surface-500">(Optional)</span></label>
          <textarea
            {...register('description')}
            rows={3}
            className="w-full rounded-lg border border-surface-700 bg-surface-900/50 px-3 py-2 text-sm text-surface-100 placeholder:text-surface-500 focus:outline-none focus:ring-2 focus:ring-primary-500/50 focus:border-primary-500/50 transition-all custom-scrollbar resize-none"
            placeholder="Add operational details..."
          />
        </div>

        <div className="flex justify-end gap-3 pt-4 border-t border-surface-800">
          <Button type="button" variant="ghost" onClick={onClose} disabled={isLoading}>
            Cancel
          </Button>
          <Button type="submit" isLoading={isLoading}>
            {product ? 'Save Changes' : 'Create Product'}
          </Button>
        </div>
      </form>
    </Modal>
  );
}

import { useState, useRef, useEffect } from 'react';
import { Upload, X, Image as ImageIcon } from 'lucide-react';
import Modal from '../ui/Modal';

const CATEGORIES = [
  'Electronics',
  'Clothing',
  'Food & Beverages',
  'Furniture',
  'Automotive',
  'Pharmaceuticals',
  'Raw Materials',
  'Machinery',
  'Packaging',
  'Other',
];

export default function ProductFormModal({ isOpen, onClose, onSubmit, product, isLoading }) {
  const isEdit = Boolean(product);
  const fileInputRef = useRef(null);

  const [form, setForm] = useState({
    name: '',
    category: '',
    description: '',
    price: '',
  });
  const [imageFile, setImageFile] = useState(null);
  const [imagePreview, setImagePreview] = useState('');
  const [errors, setErrors] = useState({});

  useEffect(() => {
    if (isOpen) {
      if (product) {
        setForm({
          name: product.name || '',
          category: product.category || '',
          description: product.description || '',
          price: product.price?.toString() || '',
        });
        setImagePreview(product.imageUrl || '');
      } else {
        setForm({ name: '', category: '', description: '', price: '' });
        setImagePreview('');
      }
      setImageFile(null);
      setErrors({});
    }
  }, [isOpen, product]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
    if (errors[name]) {
      setErrors((prev) => ({ ...prev, [name]: '' }));
    }
  };

  const handleImageSelect = (e) => {
    const file = e.target.files[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) {
        setErrors((prev) => ({ ...prev, image: 'Image must be less than 5MB' }));
        return;
      }
      setImageFile(file);
      const reader = new FileReader();
      reader.onloadend = () => setImagePreview(reader.result);
      reader.readAsDataURL(file);
      setErrors((prev) => ({ ...prev, image: '' }));
    }
  };

  const removeImage = () => {
    setImageFile(null);
    setImagePreview('');
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const validate = () => {
    const newErrors = {};
    if (!form.name.trim()) newErrors.name = 'Product name is required';
    if (!form.category) newErrors.category = 'Category is required';
    if (!form.price || isNaN(form.price) || parseFloat(form.price) < 0) {
      newErrors.price = 'Valid price is required';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!validate()) return;

    const formData = new FormData();
    formData.append('name', form.name.trim());
    formData.append('category', form.category);
    formData.append('description', form.description.trim());
    formData.append('price', form.price);
    if (imageFile) {
      formData.append('image', imageFile);
    }

    onSubmit(formData);
  };

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={isEdit ? 'Edit Product' : 'Add New Product'} size="lg">
      <form onSubmit={handleSubmit} className="space-y-5">
        {/* Image Upload */}
        <div>
          <label className="label-text">Product Image</label>
          <div
            className={`relative border-2 border-dashed rounded-xl transition-all duration-200 overflow-hidden
                        ${
                          imagePreview
                            ? 'border-primary-500/30 bg-primary-600/5'
                            : 'border-surface-700/50 hover:border-surface-600/50 bg-surface-900/30'
                        }
                        ${errors.image ? 'border-danger-500/50' : ''}`}
          >
            {imagePreview ? (
              <div className="relative group">
                <img
                  src={imagePreview}
                  alt="Preview"
                  className="w-full h-48 object-cover"
                />
                <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 
                                transition-opacity flex items-center justify-center">
                  <button
                    type="button"
                    onClick={removeImage}
                    className="p-2 rounded-xl bg-danger-600 text-white hover:bg-danger-500 transition-colors"
                  >
                    <X size={20} />
                  </button>
                </div>
              </div>
            ) : (
              <button
                type="button"
                onClick={() => fileInputRef.current?.click()}
                className="w-full py-10 flex flex-col items-center gap-3"
              >
                <div className="p-3 rounded-xl bg-surface-800/50">
                  <Upload size={24} className="text-surface-400" />
                </div>
                <div className="text-center">
                  <p className="text-sm text-surface-300">Click to upload image</p>
                  <p className="text-xs text-surface-500 mt-1">PNG, JPG, GIF, WebP up to 5MB</p>
                </div>
              </button>
            )}
            <input
              ref={fileInputRef}
              type="file"
              accept="image/*"
              onChange={handleImageSelect}
              className="hidden"
              id="product-image-input"
            />
          </div>
          {errors.image && <p className="text-danger-400 text-xs mt-1">{errors.image}</p>}
        </div>

        {/* Name */}
        <div>
          <label htmlFor="product-name" className="label-text">
            Product Name <span className="text-danger-400">*</span>
          </label>
          <input
            id="product-name"
            name="name"
            type="text"
            value={form.name}
            onChange={handleChange}
            placeholder="Enter product name"
            className={`input-field ${errors.name ? 'border-danger-500/50 focus:border-danger-500/50' : ''}`}
          />
          {errors.name && <p className="text-danger-400 text-xs mt-1">{errors.name}</p>}
        </div>

        {/* Category */}
        <div>
          <label htmlFor="product-category" className="label-text">
            Category <span className="text-danger-400">*</span>
          </label>
          <div className="relative">
            <select
              id="product-category"
              name="category"
              value={form.category}
              onChange={handleChange}
              className={`select-field ${errors.category ? 'border-danger-500/50' : ''} ${
                !form.category ? 'text-surface-500' : ''
              }`}
            >
              <option value="">Select a category</option>
              {CATEGORIES.map((cat) => (
                <option key={cat} value={cat}>
                  {cat}
                </option>
              ))}
            </select>
          </div>
          {errors.category && <p className="text-danger-400 text-xs mt-1">{errors.category}</p>}
        </div>

        {/* Price */}
        <div>
          <label htmlFor="product-price" className="label-text">
            Price ($) <span className="text-danger-400">*</span>
          </label>
          <input
            id="product-price"
            name="price"
            type="number"
            step="0.01"
            min="0"
            value={form.price}
            onChange={handleChange}
            placeholder="0.00"
            className={`input-field ${errors.price ? 'border-danger-500/50' : ''}`}
          />
          {errors.price && <p className="text-danger-400 text-xs mt-1">{errors.price}</p>}
        </div>

        {/* Description */}
        <div>
          <label htmlFor="product-description" className="label-text">
            Description
          </label>
          <textarea
            id="product-description"
            name="description"
            value={form.description}
            onChange={handleChange}
            placeholder="Enter product description (optional)"
            rows={3}
            className="input-field resize-none"
          />
        </div>

        {/* Actions */}
        <div className="flex items-center justify-end gap-3 pt-2">
          <button type="button" onClick={onClose} className="btn-secondary" id="product-form-cancel-btn">
            Cancel
          </button>
          <button type="submit" className="btn-primary" disabled={isLoading} id="product-form-submit-btn">
            {isLoading ? (
              <span className="flex items-center gap-2">
                <svg className="animate-spin h-4 w-4" viewBox="0 0 24 24">
                  <circle
                    className="opacity-25"
                    cx="12"
                    cy="12"
                    r="10"
                    stroke="currentColor"
                    strokeWidth="4"
                    fill="none"
                  />
                  <path
                    className="opacity-75"
                    fill="currentColor"
                    d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"
                  />
                </svg>
                {isEdit ? 'Updating...' : 'Creating...'}
              </span>
            ) : isEdit ? (
              'Update Product'
            ) : (
              'Create Product'
            )}
          </button>
        </div>
      </form>
    </Modal>
  );
}

